const epKey = (method, path) => method + "::" + path;

export function useEndpointToggle(pageKey) {
  const endpoints = PAGE_ENDPOINTS[pageKey] || [];
  const [states, setStates]   = useState({});
  const [loading, setLoading] = useState(true);
  const [saving, setSaving]   = useState({});
  const loaded = useRef(false);

  useEffect(() => {
    if (loaded.current || endpoints.length === 0) { setLoading(false); return; }
    loaded.current = true;
    axiosInstance.get("/admin-panel/endpoint-toggles/")
      .then(res => {
        const list = res.data?.results ?? (Array.isArray(res.data) ? res.data : []);
        const map = {};
        list.forEach(t => { map[epKey(t.method, t.path)] = { id: t.id, is_enabled: t.is_enabled }; });
        setStates(map);
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [pageKey]);

  const isOn = useCallback((method, path) =>
    states[epKey(method, path)]?.is_enabled !== false,
  [states]);

  const toggle = useCallback(async (ep) => {
    const k    = epKey(ep.method, ep.path);
    const next = !isOn(ep.method, ep.path);
    setSaving(p => ({ ...p, [k]: true }));
    try {
      const ex = states[k];
      let r;
      if (ex?.id) {
        r = (await axiosInstance.patch(`/admin-panel/endpoint-toggles/${ex.id}/`, { is_enabled: next })).data;
      } else {
        r = (await axiosInstance.post("/admin-panel/endpoint-toggles/", {
          path: ep.path, method: ep.method, group: ep.group,
          label: ep.label || ep.path, is_enabled: next,
          disabled_message: "This feature is temporarily disabled.",
        })).data;
      }
      setStates(p => ({ ...p, [k]: { id: r.id, is_enabled: next } }));
    } catch(e) {}
    finally { setSaving(p => ({ ...p, [k]: false })); }
  }, [states, isOn]);

  const bulkToggle = useCallback(async (eps, next) => {
    const toggles = eps.map(ep => ({
      path: ep.path, method: ep.method, group: ep.group,
      label: ep.label || ep.path, is_enabled: next,
      disabled_message: "This feature is temporarily disabled.",
    }));
    try {
      for (let i = 0; i < toggles.length; i += 200)
        await axiosInstance.post("/admin-panel/endpoint-toggles/bulk_toggle/",
          { toggles: toggles.slice(i, i + 200) });
      setStates(p => {
        const n = { ...p };
        eps.forEach(ep => { n[epKey(ep.method, ep.path)] = { ...p[epKey(ep.method, ep.path)], is_enabled: next }; });
        return n;
      });
    } catch(e) {}
  }, []);

  const activeCount = endpoints.filter(ep => isOn(ep.method, ep.path)).length;
  const totalCount  = endpoints.length;

  return { endpoints, states, loading, saving, isOn, toggle, bulkToggle, activeCount, totalCount };
}
